"use client";

import { useLocale } from "next-intl";
import { useEffect, useState } from "react";
import { useRouter } from "next/navigation";
import Pagination from "@/components/Pagination";
import ProductCard from "@/components/ProductCard";
import { useProductsByCategory } from "@/hooks/useProductsByCategory";
import type { PagedResult, ProductByCategoryDto } from "@/lib/api/productsByCategory";

interface ProductsByCategoryListProps {
  categoryId: number;
}

export default function ProductsByCategoryList({ categoryId }: ProductsByCategoryListProps) {
  const locale = useLocale();
  const router = useRouter();
  const [page, setPage] = useState(1);
  const pageSize = 10;

  useEffect(() => {
    setPage(1);
  }, [categoryId]);

  const { data, isLoading, isError, error, refetch } = useProductsByCategory({
    categoryId,
    page,
    pageSize,
  });

  const paged = data as PagedResult<ProductByCategoryDto> | undefined;
  const items = paged?.items ?? [];
  const totalPages = paged?.totalPages ?? 1;

  return (
    <div className="space-y-4">
      {isLoading ? (
        <div className="rounded-xl border border-slate-200 bg-white px-4 py-6 text-sm text-slate-600 shadow-sm">
          {locale === "vi" ? "Đang tải sản phẩm..." : "Loading products..."}
        </div>
      ) : isError ? (
        <div className="rounded-xl border border-red-200 bg-red-50 px-4 py-6 text-sm text-red-700 shadow-sm">
          {error instanceof Error
            ? error.message
            : locale === "vi"
              ? "Không tải được sản phẩm."
              : "Unable to load products."}
          <button
            className="ml-3 rounded-md border border-red-200 px-3 py-1 text-xs font-medium text-red-700 hover:bg-red-100"
            onClick={() => refetch()}
          >
            {locale === "vi" ? "Thử lại" : "Retry"}
          </button>
        </div>
      ) : items.length === 0 ? (
        <div className="rounded-xl border border-slate-200 bg-white px-4 py-6 text-sm text-slate-600 shadow-sm">
          {locale === "vi" ? "Chưa có sản phẩm." : "No products found."}
        </div>
      ) : (
        <>
          <div className="grid gap-4 sm:grid-cols-2 md:grid-cols-3 lg:grid-cols-4 xl:grid-cols-5 2xl:grid-cols-5">
            {items.map((product) => {
              const displayName = locale === "vi" ? product.name : product.nameEn || product.name;
              return (
                <ProductCard
                  key={product.id}
                  product={product}
                  displayName={displayName}
                  onAddToCart={() => console.log("add-to-cart", product)}
                  onBuyNow={() => console.log("buy-now", product)}
                  onClick={(p) => router.push(`/${locale}/products/${p.id}`)}
                />
              );
            })}
          </div>

          <Pagination currentPage={page} totalPages={totalPages} onPageChange={setPage} />
        </>
      )}
    </div>
  );
}
