"use client";

import MainLayout from "@/components/MainLayout";
import ProductCard from "@/components/ProductCard";
import ProductsByCategoryList from "@/components/ProductsByCategoryList";
import { useCategorySelection } from "@/components/layout/CategorySelectionContext";
import { products } from "@/data/products";
import { useLocale, useTranslations } from "next-intl";
import { useRouter } from "next/navigation";

function CategoryProductsPanel() {
  const locale = useLocale();
  const { selectedCategoryId } = useCategorySelection();

  return (
    <div className="rounded-xl border border-slate-200 bg-white/90 p-4 shadow-sm">
      <div className="mb-3 flex items-center justify-between">
        <h2 className="text-lg font-semibold text-slate-900">
          {selectedCategoryId
            ? locale === "vi"
              ? "Sản phẩm theo danh mục"
              : "Products by category"
            : locale === "vi"
              ? "Chọn danh mục bên trái"
              : "Choose a category on the left"}
        </h2>
      </div>
      {selectedCategoryId ? (
        <ProductsByCategoryList categoryId={selectedCategoryId} />
      ) : (
        <div className="rounded-lg border border-dashed border-slate-200 bg-slate-50 px-4 py-6 text-sm text-slate-600">
          {locale === "vi"
            ? "Chọn một danh mục ở thanh bên trái để xem sản phẩm."
            : "Select a category from the sidebar to view products."}
        </div>
      )}
    </div>
  );
}

export default function HomePage() {
  const t = useTranslations("Home");
  const router = useRouter();
  const locale = useLocale();

  return (
    <MainLayout>
      <section className="space-y-6">
        <div className="text-sm text-slate-600">Trang chu / Danh muc / ...</div>

        <div className="rounded-xl bg-gradient-to-r from-primary to-primary-light p-8 text-white shadow-lg sm:p-10">
          <div className="space-y-4">
            <p className="text-xs uppercase tracking-[0.3em] text-white/70">TME</p>
            <h1 className="text-3xl font-semibold sm:text-4xl">{t("hero.title")}</h1>
            <p className="max-w-2xl text-sm text-white/90">{t("hero.subtitle")}</p>
            <button className="rounded-full bg-slate-900/80 px-5 py-2 text-sm font-semibold uppercase tracking-widest text-white transition hover:bg-slate-900">
              {t("hero.button")}
            </button>
          </div>
        </div>

        <CategoryProductsPanel />

        <div>
          <div className="mb-3 flex items-center justify-between">
            <h2 className="text-lg font-semibold text-slate-800">{t("featured.title")}</h2>
            <button className="text-sm font-medium text-primary hover:text-primary-dark">
              {t("featured.viewAll")}
            </button>
          </div>
          <div className="grid gap-4 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 2xl:grid-cols-5">
            {products.map((product) => {
              const displayName = locale === "vi" ? product.name : product.name;
              const mappedProduct = {
                id: Number(product.id) || 0,
                code: product.code,
                name: product.name,
                nameEn: product.name,
                price: product.price,
                originalPrice: product.oldPrice ?? null,
                saleOff: product.discountPercent ?? 0,
                imageUrl: product.imageUrl,
                categoryId: 0,
                categoryName: product.category,
                isNew: false,
                isActive: true,
                quantity: product.stockQuantity ?? (product.inStock ? 1 : 0),
                dateAdded: "",
              };
              return (
                <ProductCard
                  key={product.id}
                  product={mappedProduct}
                  displayName={displayName}
                  onAddToCart={() => console.log("add-to-cart", mappedProduct)}
                  onBuyNow={() => console.log("buy-now", mappedProduct)}
                  onClick={(p) => router.push(`/${locale}/products/${p.id}`)}
                />
              );
            })}
          </div>
        </div>
      </section>
    </MainLayout>
  );
}
