"use client";

import type { ComponentProps } from "react";
import { useEffect, useMemo, useState } from "react";
import {
  Sidebar,
  SidebarCollapse,
  SidebarItem,
  SidebarItemGroup,
  SidebarItems,
} from "flowbite-react";
import { useLocale, useTranslations } from "next-intl";
import { useCategories } from "@/hooks/useCategories";
import type { CategoryDto } from "@/lib/api/categories";
import { useCategorySelection } from "./CategorySelectionContext";

function getCategoryLabel(category: CategoryDto, locale: string) {
  if (locale === "vi") return category.name;
  return category.nameEn?.trim() ? category.nameEn : category.name;
}

function filterTree(nodes: CategoryDto[], term: string, locale: string): CategoryDto[] {
  if (!term.trim()) return nodes;
  const q = term.toLowerCase();

  const walk = (list: CategoryDto[]): CategoryDto[] => {
    const result: CategoryDto[] = [];
    for (const node of list) {
      const label = getCategoryLabel(node, locale).toLowerCase();
      const children = node.children ? walk(node.children) : [];
      if (label.includes(q) || children.length) {
        result.push({
          ...node,
          children: children.length ? children : undefined,
        });
      }
    }
    return result;
  };

  return walk(nodes);
}

function collectIds(nodes: CategoryDto[]): number[] {
  const ids: number[] = [];
  const walk = (list: CategoryDto[]) => {
    for (const node of list) {
      ids.push(node.id);
      if (node.children?.length) walk(node.children);
    }
  };
  walk(nodes);
  return ids;
}

interface CategoryNodeProps {
  category: CategoryDto;
  depth?: number;
  locale: string;
  openIds: Set<number>;
  toggle: (id: number) => void;
  selectedId: number | null;
  onSelect: (id: number) => void;
}

function CategoryNode({
  category,
  depth = 0,
  locale,
  openIds,
  toggle,
  selectedId,
  onSelect,
}: CategoryNodeProps) {
  const label = getCategoryLabel(category, locale);
  const paddingLeft = depth > 0 ? depth * 12 : 0;
  const itemStyle = paddingLeft ? { paddingLeft: `${paddingLeft}px` } : undefined;
  const hasChildren = Boolean(category.children?.length);
  const isOpen = hasChildren && openIds.has(category.id);
  const isSelected = selectedId === category.id;

  const depthClass =
    depth === 0
      ? "bg-orange-50/80 text-[#EE4D2D] border border-orange-100"
      : depth === 1
        ? "bg-slate-50 text-slate-800"
        : "text-slate-800";
  const lineClass =
    depth >= 2 ? "relative before:absolute before:left-0 before:top-0 before:bottom-0 before:w-px before:bg-slate-200" : "";

  if (hasChildren) {
    return (
      <SidebarCollapse
        key={category.id}
        label={label}
        open={isOpen}
        onClick={() => toggle(category.id)}
        style={itemStyle}
        className={`w-full rounded-lg px-2 py-1.5 text-sm font-medium hover:bg-orange-50 hover:text-[#EE4D2D] data-[active=true]:bg-orange-50 data-[active=true]:text-[#EE4D2D] ${depthClass} ${lineClass}`}
      >
        <div
          className={`${isOpen ? "block" : "hidden"} ${depth >= 1 ? "pl-3" : ""} ${depth >= 1 ? "border-l border-slate-200" : ""}`}
          style={{ overflowX: "hidden" }}
        >
          {category.children?.map((child) => (
            <CategoryNode
              key={child.id}
              category={child}
              depth={depth + 1}
              locale={locale}
              openIds={openIds}
              toggle={toggle}
              selectedId={selectedId}
              onSelect={onSelect}
            />
          ))}
        </div>
      </SidebarCollapse>
    );
  }

  return (
    <button
      type="button"
      onClick={() => onSelect(category.id)}
      className={`w-full text-left rounded-lg px-2 py-1.5 text-sm text-slate-700 hover:bg-orange-50 hover:text-[#EE4D2D] ${
        isSelected ? "border border-orange-200 bg-orange-50 text-[#EE4D2D]" : ""
      } ${depthClass} ${lineClass}`}
      style={itemStyle}
    >
      <span className="flex-1 text-left text-xs text-slate-700 break-words">{label}</span>
    </button>
  );
}

export default function CategorySidebar() {
  const t = useTranslations("Sidebar");
  const locale = useLocale();
  const { selectedCategoryId, selectCategory } = useCategorySelection();
  const [query, setQuery] = useState("");
  const [openIds, setOpenIds] = useState<Set<number>>(new Set());
  const { data, isLoading, isError, error } = useCategories();
  const categories = data ?? [];
  const filtered = useMemo(
    () => filterTree(categories, query, locale),
    [categories, query, locale],
  );
  useEffect(() => {
    if (filtered.length && query.trim()) {
      setOpenIds(new Set(collectIds(filtered)));
    } else if (!query.trim()) {
      setOpenIds(new Set());
    }
  }, [filtered, query]);

  const toggleOpen = (id: number) => {
    setOpenIds((prev) => {
      const next = new Set(prev);
      if (next.has(id)) next.delete(id);
      else next.add(id);
      return next;
    });
  };
  const hasQuery = query.trim().length > 0;
  const errorMessage =
    isError &&
    (error instanceof Error
      ? error.message
      : locale === "vi"
        ? "Khong tai duoc danh muc."
        : "Unable to load categories.");

  return (
    <aside className="sticky top-24 max-h-[calc(100vh-120px)] overflow-y-auto overflow-x-hidden rounded-2xl bg-white/95 p-3 shadow-sm ring-1 ring-slate-100 backdrop-blur">
      <Sidebar aria-label={t("title")} className="h-full w-full bg-transparent p-0">
        <div className="mb-3 flex items-start gap-2 rounded-xl bg-gradient-to-r from-orange-50/80 to-white p-3">
          <span className="inline-flex h-8 w-8 shrink-0 items-center justify-center rounded-lg bg-orange-100 text-[#EE4D2D] shadow-inner">
            <svg
              xmlns="http://www.w3.org/2000/svg"
              className="h-4 w-4"
              viewBox="0 0 24 24"
              fill="none"
              stroke="currentColor"
              strokeWidth="2"
              strokeLinecap="round"
              strokeLinejoin="round"
            >
              <line x1="8" x2="21" y1="6" y2="6" />
              <line x1="8" x2="21" y1="12" y2="12" />
              <line x1="8" x2="21" y1="18" y2="18" />
              <line x1="3" x2="3.01" y1="6" y2="6" />
              <line x1="3" x2="3.01" y1="12" y2="12" />
              <line x1="3" x2="3.01" y1="18" y2="18" />
            </svg>
          </span>
          <div className="min-w-0">
            <h2 className="text-sm font-semibold text-slate-900">
              {t("panelTitle")}
            </h2>
            <p className="mt-1 text-xs text-slate-500">
              {t("panelDescription")}
            </p>
          </div>
        </div>

        <div className="mb-3">
          <div className="relative">
            <input
              value={query}
              onChange={(e) => setQuery(e.target.value)}
              type="text"
              placeholder={t("searchPlaceholder")}
              className="w-full rounded-lg border border-slate-200 bg-white px-3 py-2 pr-10 text-sm text-slate-700 shadow-inner focus:border-orange-300 focus:outline-none focus:ring-2 focus:ring-orange-100"
            />
            {hasQuery ? (
              <button
                type="button"
                onClick={() => setQuery("")}
                className="absolute right-2 top-1/2 flex h-7 w-7 -translate-y-1/2 items-center justify-center rounded-full bg-slate-100 text-slate-500 transition hover:bg-slate-200 hover:text-slate-700"
                aria-label={locale === "vi" ? "Xoa tim kiem" : "Clear search"}
              >
                <ClearIcon className="h-3.5 w-3.5" />
              </button>
            ) : (
              <span className="pointer-events-none absolute right-3 top-1/2 -translate-y-1/2 text-slate-400">
                <SearchIcon className="h-4 w-4" />
              </span>
            )}
          </div>
        </div>

        <SidebarItems className="overflow-x-hidden">
          {isLoading ? (
            <div className="px-3 pb-3 text-sm text-slate-500">
              {locale === "vi" ? "Dang tai danh muc..." : "Loading categories..."}
            </div>
          ) : errorMessage ? (
            <div className="px-3 pb-3 text-sm text-red-600">{errorMessage}</div>
          ) : filtered.length ? (
            <SidebarItemGroup className="space-y-1">
              {filtered.map((category) => (
                <CategoryNode
                  key={category.id}
                  category={category}
                  depth={0}
                  locale={locale}
                  openIds={openIds}
                  toggle={toggleOpen}
                  selectedId={selectedCategoryId}
                  onSelect={selectCategory}
                />
              ))}
            </SidebarItemGroup>
          ) : (
            <div className="px-3 pb-3 text-sm text-slate-500">
              {t("noResults")}
            </div>
          )}
        </SidebarItems>
      </Sidebar>
    </aside>
  );
}

function SearchIcon(props: ComponentProps<"svg">) {
  return (
    <svg
      xmlns="http://www.w3.org/2000/svg"
      className="h-4 w-4"
      viewBox="0 0 20 20"
      fill="currentColor"
      {...props}
    >
      <path
        fillRule="evenodd"
        d="M12.9 14.32a6 6 0 1 1 1.414-1.414l2.387 2.387a1 1 0 0 1-1.414 1.414L12.9 14.32ZM12 9a4 4 0 1 0-8 0 4 4 0 0 0 8 0Z"
        clipRule="evenodd"
      />
    </svg>
  );
}

function ClearIcon(props: ComponentProps<"svg">) {
  return (
    <svg
      xmlns="http://www.w3.org/2000/svg"
      viewBox="0 0 20 20"
      fill="none"
      stroke="currentColor"
      strokeWidth="1.8"
      strokeLinecap="round"
      strokeLinejoin="round"
      {...props}
    >
      <line x1="5" y1="5" x2="15" y2="15" />
      <line x1="5" y1="15" x2="15" y2="5" />
    </svg>
  );
}
