"use client";

import { useState } from "react";
import Header from "./Header";
import CategorySidebar from "./layout/CategorySidebar";
import Footer from "./Footer";
import { CategorySelectionProvider } from "./layout/CategorySelectionContext";

interface MainLayoutProps {
  children: React.ReactNode;
}

export default function MainLayout({ children }: MainLayoutProps) {
  const [sidebarOpen, setSidebarOpen] = useState(false);

  return (
    <CategorySelectionProvider>
      <div className="min-h-screen bg-background">
        <Header onToggleSidebar={() => setSidebarOpen((prev) => !prev)} />

      <div className="mx-auto flex w-full max-w-[1400px] gap-5 px-4 py-6 lg:px-6">
        <aside className="hidden w-64 shrink-0 lg:block">
          <CategorySidebar />
        </aside>

        <main className="flex-1">
          <div className="rounded-xl border border-slate-200 bg-white/80 p-5 shadow-sm">
            {children}
          </div>
        </main>
      </div>

      {/* Mobile sidebar drawer */}
      <div
        className={`fixed inset-0 z-50 bg-black/40 transition-opacity duration-200 lg:hidden ${
          sidebarOpen ? "opacity-100" : "pointer-events-none opacity-0"
        }`}
        onClick={() => setSidebarOpen(false)}
      >
        <div
          className={`absolute inset-y-0 left-0 w-72 max-w-[80vw] transform bg-white shadow-xl transition-transform duration-200 ${
            sidebarOpen ? "translate-x-0" : "-translate-x-full"
          }`}
          onClick={(e) => e.stopPropagation()}
        >
          <div className="h-full p-3">
            <CategorySidebar />
          </div>
        </div>
      </div>

        <Footer />
      </div>
    </CategorySelectionProvider>
  );
}
