"use client";

import type { ComponentProps } from "react";
import Link from "next/link";
import { usePathname, useRouter } from "next/navigation";
import {
  Navbar,
  NavbarCollapse,
  NavbarLink,
  NavbarToggle,
} from "flowbite-react";
import { useLocale, useTranslations } from "next-intl";
import { useEffect, useMemo, useRef, useState } from "react";
import type { User } from "@/types/auth";

const navItems = (locale: string) => [
  { key: "nav.home", href: `/${locale}` },
  { key: "nav.about", href: "#" },
  { key: "nav.support", href: "#" },
  { key: "nav.newItems", href: `/${locale}/new-products` },
  { key: "nav.promo", href: "#" },
  { key: "nav.order", href: "#" },
  { key: "nav.contact", href: "#" },
];

interface HeaderProps {
  onToggleSidebar: () => void;
}

const SearchIcon = (props: ComponentProps<"svg">) => (
  <svg
    xmlns="http://www.w3.org/2000/svg"
    className="h-4 w-4 text-slate-500"
    viewBox="0 0 20 20"
    fill="currentColor"
    {...props}
  >
    <path
      fillRule="evenodd"
      d="M12.9 14.32a6 6 0 1 1 1.414-1.414l2.387 2.387a1 1 0 0 1-1.414 1.414L12.9 14.32ZM12 9a4 4 0 1 0-8 0 4 4 0 0 0 8 0Z"
      clipRule="evenodd"
    />
  </svg>
);

export default function Header({ onToggleSidebar }: HeaderProps) {
  const t = useTranslations("Header");
  const locale = useLocale();
  const pathname = usePathname() || "/";
  const router = useRouter();
  const [user, setUser] = useState<User | null>(null);
  const [dropdownOpen, setDropdownOpen] = useState(false);
  const dropdownRef = useRef<HTMLDivElement>(null);

  const trimLocale = (path: string) => path.replace(/^\/(vi|en)/, "") || "/";
  const ensureLeadingSlash = (path: string) => (path.startsWith("/") ? path : `/${path}`);
  const normalizedPath = ensureLeadingSlash(trimLocale(pathname));
  const localizedPath = (targetLocale: string) => {
    const suffix = normalizedPath === "/" ? "" : normalizedPath;
    return `/${targetLocale}${suffix}`;
  };

  useEffect(() => {
    let mounted = true;
    fetch("/api/auth/me")
      .then((res) => res.json())
      .then((data) => {
        if (!mounted) return;
        setUser(data.user);
      })
      .catch(() => {
        if (!mounted) return;
        setUser(null);
      });
    return () => {
      mounted = false;
    };
  }, []);

  useEffect(() => {
    const handler = (event: MouseEvent) => {
      if (dropdownRef.current && !dropdownRef.current.contains(event.target as Node)) {
        setDropdownOpen(false);
      }
    };
    document.addEventListener("mousedown", handler);
    return () => document.removeEventListener("mousedown", handler);
  }, []);

  const initials = useMemo(() => {
    if (!user?.fullName && !user?.email) return "U";
    const source = user.fullName || user.email;
    const parts = source.split(" ");
    if (parts.length === 1) return parts[0][0]?.toUpperCase() ?? "U";
    return (parts[0][0] + parts[parts.length - 1][0]).toUpperCase();
  }, [user]);

  const handleLogout = async () => {
    await fetch("/api/auth/logout", { method: "POST" });
    setUser(null);
    setDropdownOpen(false);
    router.push(`/${locale}`);
  };

  return (
    <header className="sticky top-0 z-40">
      <div className="bg-gradient-to-r from-slate-900 via-slate-800 to-slate-900 text-white shadow">
        <div className="mx-auto flex max-w-6xl items-center gap-4 px-4 py-4">
          <div className="flex items-center gap-3">
            <button
              onClick={onToggleSidebar}
              className="inline-flex h-10 w-10 items-center justify-center rounded-lg border border-slate-700 bg-slate-800 text-slate-100 transition hover:border-primary hover:text-primary md:hidden"
              aria-label="Mo danh muc"
            >
              <svg
                xmlns="http://www.w3.org/2000/svg"
                className="h-5 w-5"
                fill="none"
                viewBox="0 0 24 24"
                stroke="currentColor"
                strokeWidth={1.8}
              >
                <path strokeLinecap="round" strokeLinejoin="round" d="M4 6h16M4 12h16M4 18h16" />
              </svg>
            </button>

            <Link href={`/${locale}`} className="flex items-center gap-2">
              <div className="flex h-11 w-11 items-center justify-center rounded-lg bg-primary text-sm font-bold text-white shadow-inner">
                TME
              </div>
              <div className="leading-tight">
                <div className="text-sm font-semibold text-white">TME</div>
                <div className="text-xs text-slate-300">Thien Minh Electronics</div>
              </div>
            </Link>
          </div>

          <div className="hidden flex-1 md:block">
            <div className="relative">
              <input
                type="search"
                placeholder={t("searchPlaceholder")}
                className="w-full rounded-full bg-slate-100/95 px-4 py-2 text-sm text-slate-800 shadow-inner focus:outline-none focus:ring-2 focus:ring-[#EE4D2D]"
              />
              <button
                type="button"
                className="absolute right-2 top-1/2 flex h-8 w-8 -translate-y-1/2 items-center justify-center rounded-full bg-primary text-white shadow hover:bg-primary-dark"
              >
                <SearchIcon className="h-4 w-4" />
              </button>
            </div>
          </div>

          <div className="hidden items-center gap-3 md:flex">
            <div className="flex items-center gap-2 rounded-lg bg-slate-800/80 px-3 py-2 text-xs text-slate-100">
              <svg
                xmlns="http://www.w3.org/2000/svg"
                className="h-5 w-5 text-slate-200"
                fill="none"
                viewBox="0 0 24 24"
                stroke="currentColor"
                strokeWidth={1.5}
              >
                <path
                  strokeLinecap="round"
                  strokeLinejoin="round"
                  d="M2.25 6.75c0 8.284 6.716 15 15 15H21a.75.75 0 0 0 .75-.75v-1.372a.75.75 0 0 0-.563-.726l-4.423-1.106a.75.75 0 0 0-.83.343l-.97 1.622a.75.75 0 0 1-.82.334 12.035 12.035 0 0 1-7.182-7.182.75.75 0 0 1 .334-.82l1.622-.97a.75.75 0 0 0 .343-.83L6.098 3.813a.75.75 0 0 0-.726-.563H4.002a.75.75 0 0 0-.75.75v2.75Z"
                />
              </svg>
              <div className="leading-tight">
                <div className="text-[11px] text-slate-300">{t("hotlineLabel")}</div>
                <div className="text-xs font-semibold text-white">028.3957.3224</div>
              </div>
            </div>

            <Link
              href={`/${locale}/account/orders`}
              className="rounded-lg border border-slate-100/70 px-3 py-2 text-xs font-semibold text-white transition hover:border-orange-500"
            >
              {t("orders")}
            </Link>

            {user ? (
              <div className="relative" ref={dropdownRef}>
                <button
                  onClick={() => setDropdownOpen((prev) => !prev)}
                  className="flex items-center gap-2 rounded-lg border border-slate-100/70 bg-slate-900/50 px-3 py-2 text-xs font-semibold text-white transition hover:border-orange-500"
                >
                  <span className="flex h-8 w-8 items-center justify-center rounded-full bg-primary text-sm font-bold text-white">
                    {initials}
                  </span>
                  <span className="hidden text-left text-xs sm:block">
                    <span className="block font-semibold">{user.fullName || user.email}</span>
                  </span>
                  <svg
                    xmlns="http://www.w3.org/2000/svg"
                    className={`h-4 w-4 transition ${dropdownOpen ? "rotate-180" : ""}`}
                    fill="none"
                    viewBox="0 0 24 24"
                    stroke="currentColor"
                    strokeWidth={1.6}
                  >
                    <path strokeLinecap="round" strokeLinejoin="round" d="M6 9l6 6 6-6" />
                  </svg>
                </button>
                {dropdownOpen ? (
                  <div className="absolute right-0 mt-2 w-56 rounded-lg border border-slate-200 bg-white py-2 text-sm text-slate-700 shadow-lg">
                    <Link
                      href={`/${locale}/account`}
                      className="block px-4 py-2 hover:bg-slate-100"
                      onClick={() => setDropdownOpen(false)}
                    >
                      {t("userMenu.myAccount")}
                    </Link>
                    <Link
                      href={`/${locale}/account/orders`}
                      className="block px-4 py-2 hover:bg-slate-100"
                      onClick={() => setDropdownOpen(false)}
                    >
                      {t("userMenu.myOrders")}
                    </Link>
                    <div className="my-1 border-t border-slate-200" />
                    <button
                      type="button"
                      className="block w-full px-4 py-2 text-left text-red-600 hover:bg-slate-100"
                      onClick={handleLogout}
                    >
                      {t("userMenu.logout")}
                    </button>
                  </div>
                ) : null}
              </div>
            ) : (
              <Link
                href={`/${locale}/auth/login`}
                className="rounded-lg border border-slate-100/70 px-3 py-2 text-xs font-semibold text-white transition hover:border-orange-500"
              >
                {t("login")}
              </Link>
            )}

            <button className="flex items-center gap-2 rounded-lg bg-slate-800/80 px-3 py-2 text-xs text-slate-100 transition hover:bg-slate-700">
              <div className="relative flex h-9 w-9 items-center justify-center rounded-full bg-slate-900">
                <svg
                  xmlns="http://www.w3.org/2000/svg"
                  className="h-5 w-5 text-white"
                  fill="none"
                  viewBox="0 0 24 24"
                  stroke="currentColor"
                  strokeWidth={1.6}
                >
                  <path
                    strokeLinecap="round"
                    strokeLinejoin="round"
                    d="M2.25 3h1.386a.75.75 0 0 1 .724.578l.383 1.722M7.5 14.25a3 3 0 0 0-3 3h15.75m-12.75-3h11.218c1.04-1.81 1.297-3.79.52-5.04-.56-.91-1.707-1.96-4.238-1.96H7.53m0 0L6.743 5.3M7.53 7.25h-2.5"
                  />
                </svg>
                <span className="absolute -right-1 -top-1 flex h-5 w-5 items-center justify-center rounded-full bg-red-500 text-[11px] font-semibold text-white">
                  2
                </span>
              </div>
              <div className="leading-tight text-left">
                <div className="text-[11px] text-slate-300">{t("cart")}</div>
                <div className="text-xs font-semibold text-white">Xem chi tiet</div>
              </div>
            </button>

            <div className="flex items-center gap-2 rounded-full border border-slate-700/80 px-3 py-1 text-[11px] text-slate-200">
              {["vi", "en"].map((lang) => (
                <Link
                  key={lang}
                  href={localizedPath(lang)}
                  className={`px-2 font-semibold transition ${
                    locale === lang ? "text-orange-300" : "text-slate-400 hover:text-white"
                  }`}
                >
                  {t(`language.${lang}`)}
                </Link>
              ))}
            </div>
          </div>
        </div>

        <div className="mx-auto flex max-w-6xl items-center gap-3 px-4 pb-4 md:hidden">
          <div className="relative flex-1">
            <input
              type="search"
              placeholder={t("searchPlaceholder")}
              className="w-full rounded-full bg-slate-100/95 px-4 py-2 text-sm text-slate-800 focus:outline-none focus:ring-2 focus:ring-[#EE4D2D]"
            />
            <button
              type="button"
              className="absolute right-2 top-1/2 flex h-8 w-8 -translate-y-1/2 items-center justify-center rounded-full bg-primary text-white shadow hover:bg-primary-dark"
            >
              <SearchIcon className="h-4 w-4" />
            </button>
          </div>
          <button className="relative flex h-11 w-11 items-center justify-center rounded-full bg-slate-800 text-white shadow">
            <svg
              xmlns="http://www.w3.org/2000/svg"
              className="h-6 w-6"
              fill="none"
              viewBox="0 0 24 24"
              stroke="currentColor"
              strokeWidth={1.6}
            >
              <path
                strokeLinecap="round"
                strokeLinejoin="round"
                d="M2.25 3h1.386a.75.75 0 0 1 .724.578l.383 1.722M7.5 14.25a3 3 0 0 0-3 3h15.75m-12.75-3h11.218c1.04-1.81 1.297-3.79.52-5.04-.56-.91-1.707-1.96-4.238-1.96H7.53m0 0L6.743 5.3M7.53 7.25h-2.5"
              />
            </svg>
            <span className="absolute -right-1 -top-1 flex h-5 w-5 items-center justify-center rounded-full bg-red-500 text-[11px] font-semibold text-white">
              2
            </span>
          </button>
        </div>
      </div>

      <div className="border-b bg-white shadow-sm">
        <div className="mx-auto flex max-w-6xl items-center gap-3 overflow-x-auto px-4 py-2">
          <Navbar fluid rounded className="w-full border-0 bg-transparent p-0 flex h-7 items-stretch gap-6 text-sm font-medium">
            <NavbarToggle className="md:hidden" />
            <NavbarCollapse>
              {navItems(locale).map((item) => (
                <NavbarLink
                  key={item.key}
                  href={item.href}
                  className="text-sm font-medium text-slate-700 hover:text-[#EE4D2D] hover:underline"
                >
                  {t(item.key)}
                </NavbarLink>
              ))}
            </NavbarCollapse>
          </Navbar>
        </div> 
      </div>

       {/* <div className="border-t border-slate-800 bg-gradient-to-b from-[#1f2933] to-[#374151]">
        <div className="mx-auto flex max-w-7xl items-center justify-center px-4">
            <nav className="flex h-11 items-stretch gap-6 text-sm font-medium text-white">
            {navItems.map((item) => (
              <Link
                key={item.key}
                href={item.href}
                className="flex items-center border-b-2 border-transparent px-1 text-white/90 transition hover:border-white/60 hover:text-white"
              >
                {t(item.key)}
              </Link>
            ))}
          </nav>
        </div>
      </div> */}

       {/* <div className="">
        <div className="mx-auto flex max-w-7xl items-center justify-center px-4">
            <nav className="flex h-11 items-stretch gap-6 text-sm font-medium text-white">
            {navItems.map((item) => (
              <Link
                key={item.key}
                href={item.href}
                className="flex items-center border-b-2 border-transparent px-1 text-white/90 transition hover:border-white/60 hover:text-white"
              >
                {t(item.key)}
              </Link>
            ))}
          </nav>
        </div>
      </div> */}
    </header>
  );
}
